import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

export const SEOHead = ({ 
    title = 'Yaa Clarence | Discipline. Wisdom. Purpose.',
    description = 'Explore the portfolio of Yaa Clarence - IT student, author, and creator of the Bruce Lee Discipline Diaries brand.',
    image = 'https://yaaclarence.com/og-image.png',
    url = 'https://yaaclarence.com',
    type = 'website'
}) => {
    const location = useLocation();
    
    useEffect(() => {
        // Update document title
        document.title = title;

        // Meta tags
        const metaTags = [
            { name: 'description', content: description },
            { name: 'viewport', content: 'width=device-width, initial-scale=1.0' },
            { name: 'theme-color', content: '#4B2F9F' },
            { name: 'keywords', content: 'Yaa Clarence, portfolio, author, Bruce Lee, discipline, masculinity' },
            
            // Open Graph
            { property: 'og:title', content: title },
            { property: 'og:description', content: description },
            { property: 'og:image', content: image },
            { property: 'og:url', content: url + location.pathname },
            { property: 'og:type', content: type },
            { property: 'og:site_name', content: 'Yaa Clarence' },
            
            // Twitter Card
            { name: 'twitter:card', content: 'summary_large_image' },
            { name: 'twitter:title', content: title },
            { name: 'twitter:description', content: description },
            { name: 'twitter:image', content: image },
            
            // Additional SEO
            { name: 'author', content: 'Yaa Clarence' },
            { name: 'copyright', content: `© ${new Date().getFullYear()} Yaa Clarence. All rights reserved.` },
            { httpEquiv: 'X-UA-Compatible', content: 'ie=edge' }
        ];

        // Remove existing meta tags and add new ones
        metaTags.forEach(tag => {
            let selector = '';
            const prop = tag.property || tag.name || tag.httpEquiv;
            
            if (tag.property) selector = `meta[property="${prop}"]`;
            else if (tag.name) selector = `meta[name="${prop}"]`;
            else if (tag.httpEquiv) selector = `meta[http-equiv="${prop}"]`;

            // Remove existing tag if it exists
            if (selector) {
                const existing = document.querySelector(selector);
                if (existing) existing.remove();
            }

            // Create and append new tag
            const meta = document.createElement('meta');
            if (tag.property) meta.setAttribute('property', tag.property);
            if (tag.name) meta.setAttribute('name', tag.name);
            if (tag.httpEquiv) meta.setAttribute('http-equiv', tag.httpEquiv);
            if (tag.content) meta.setAttribute('content', tag.content);
            
            document.head.appendChild(meta);
        });

        // Add canonical URL
        let canonical = document.querySelector('link[rel="canonical"]');
        if (!canonical) {
            canonical = document.createElement('link');
            canonical.rel = 'canonical';
            document.head.appendChild(canonical);
        }
        canonical.href = url + location.pathname;

        // Add structured data (JSON-LD)
        const structuredData = {
            '@context': 'https://schema.org',
            '@type': 'Person',
            name: 'Yaa Clarence',
            url: url,
            image: image,
            description: description,
            jobTitle: 'IT Student & Author',
            sameAs: [
                'https://facebook.com/yaaclarence',
                'https://tiktok.com/@yaaclarence',
                'https://linkedin.com/in/yaaclarence',
                'https://github.com/yaaclarence'
            ]
        };

        let script = document.querySelector('script[type="application/ld+json"]');
        if (!script) {
            script = document.createElement('script');
            script.type = 'application/ld+json';
            document.head.appendChild(script);
        }
        script.textContent = JSON.stringify(structuredData);

    }, [title, description, image, url, location.pathname]);

    return null; // This component doesn't render anything
};

export default SEOHead;

import React, { createContext, useContext, useState, useEffect } from 'react';

const themes = ['theme-default', 'theme-dark-discipline', 'theme-midnight-purpose'];
const defaultTheme = 'theme-default';

const ThemeContext = createContext({
    theme: defaultTheme,
    toggleTheme: () => { }
});

export const useTheme = () => useContext(ThemeContext);

export const ThemeProvider = ({ children }) => {
    const [theme, setTheme] = useState(() => {
        return localStorage.getItem('yaa_clarence_theme') || defaultTheme;
    });

    useEffect(() => {
        // Remove all theme classes and add the current one directly to body/html
        document.documentElement.classList.remove(...themes);
        if (theme !== 'theme-default') {
            document.documentElement.classList.add(theme);
        }
        localStorage.setItem('yaa_clarence_theme', theme);
    }, [theme]);

    const toggleTheme = () => {
        const currentIndex = themes.indexOf(theme);
        const nextIndex = (currentIndex + 1) % themes.length;
        setTheme(themes[nextIndex]);
    };

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};

import { useState, useEffect, useCallback } from 'react';
import { NavLink, Link, useLocation } from 'react-router-dom';
import { List, X, Sun, Moon, Star } from '@phosphor-icons/react';
import { motion } from 'framer-motion';
import { useTheme } from '../ThemeProvider';

const Navbar = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const { theme, toggleTheme } = useTheme();
    const location = useLocation();

    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 50);
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    // Close mobile menu on route change
    useEffect(() => { setIsOpen(false); }, [location]);

    const scrollToTop = (e) => {
        if (location.pathname === '/') {
            e.preventDefault();
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const renderThemeIcon = () => {
        if (theme === 'theme-default') return <Sun size={20} />;
        if (theme === 'theme-midnight-purpose') return <Star size={20} />;
        return <Moon size={20} />;
    };

    const links = [
        { name: 'About', to: '/about' },
        { name: 'Books', to: '/books' },
        { name: 'BLDD', to: '/bruce-lee-diaries' },
        { name: 'Blog', to: '/blog' },
        { name: 'Projects', to: '/projects' },
        { name: 'Contact', to: '/contact' },
    ];

    const mobileMenuVariants = {
        hidden: { opacity: 0, y: -100 },
        visible: {
            opacity: 1,
            y: 0,
            transition: {
                duration: 0.3,
                staggerChildren: 0.05,
            },
        },
        exit: { opacity: 0, y: -100, transition: { duration: 0.2 } },
    };

    const mobileItemVariants = {
        hidden: { opacity: 0, y: -20 },
        visible: { opacity: 1, y: 0 },
    };

    return (
        <nav className={`sticky top-0 z-50 transition-all duration-300 ${scrolled ? 'bg-card-bg/95 backdrop-blur-md shadow-md' : 'bg-primary-bg'}`}>
            <div className="container mx-auto px-4 py-4 flex justify-between items-center relative z-50">
                <motion.div
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                >
                    <Link to="/" onClick={scrollToTop} className="text-2xl font-heading font-black text-primary-accent uppercase tracking-widest cursor-pointer">
                        Yaa Clarence
                    </Link>
                </motion.div>
                <div className="hidden md:flex space-x-8 items-center">
                    {links.map((link) => (
                        <motion.div
                            key={link.name}
                            whileHover={{ y: -2 }}
                            whileTap={{ scale: 0.95 }}
                        >
                            <NavLink
                                to={link.to}
                                className={({ isActive }) =>
                                    `font-heading text-sm uppercase tracking-wider font-medium transition-colors ${isActive ? 'text-primary-accent' : 'text-primary-text hover:text-primary-accent'}`
                                }
                            >
                                {link.name}
                            </NavLink>
                        </motion.div>
                    ))}
                    <motion.button
                        onClick={toggleTheme}
                        className="p-2 ml-2 border border-border rounded-full hover:bg-secondary-bg text-primary-text transition-colors"
                        title="Toggle Theme"
                        whileHover={{ rotate: 180, scale: 1.1 }}
                        whileTap={{ scale: 0.9 }}
                        transition={{ duration: 0.3 }}
                    >
                        {renderThemeIcon()}
                    </motion.button>
                </div>
                {/* Mobile Icons */}
                <div className="md:hidden flex items-center space-x-3">
                    <motion.button
                        onClick={toggleTheme}
                        className="p-2 rounded-full hover:bg-secondary-bg text-primary-text transition-colors"
                        whileHover={{ rotate: 180, scale: 1.1 }}
                        whileTap={{ scale: 0.9 }}
                        transition={{ duration: 0.3 }}
                    >
                        {renderThemeIcon()}
                    </motion.button>
                    <motion.button
                        className="text-primary-text p-2"
                        onClick={() => setIsOpen(!isOpen)}
                        whileHover={{ scale: 1.1 }}
                        whileTap={{ scale: 0.9 }}
                    >
                        {isOpen ? <X size={28} weight="regular" /> : <List size={28} weight="regular" />}
                    </motion.button>
                </div>
            </div>

            {/* Full Screen Mobile Menu */}
            <motion.div
                className={`fixed inset-0 bg-primary-bg z-40 flex flex-col justify-center items-center md:hidden ${isOpen ? 'pointer-events-auto' : 'pointer-events-none'}`}
                animate={isOpen ? 'visible' : 'hidden'}
                variants={mobileMenuVariants}
                initial="hidden"
            >
                <motion.div
                    className="flex flex-col items-center space-y-10"
                    variants={{
                        hidden: { opacity: 0 },
                        visible: {
                            opacity: 1,
                            transition: {
                                staggerChildren: 0.1,
                            },
                        },
                    }}
                >
                    <motion.div variants={mobileItemVariants}>
                        <Link to="/" onClick={scrollToTop} className="text-3xl font-heading font-black uppercase tracking-widest hover:text-primary-accent transition-colors">Home</Link>
                    </motion.div>
                    {links.map((link) => (
                        <motion.div key={link.name} variants={mobileItemVariants}>
                            <Link
                                to={link.to}
                                className="text-3xl font-heading font-black uppercase tracking-widest hover:text-primary-accent transition-colors"
                            >
                                {link.name}
                            </Link>
                        </motion.div>
                    ))}
                </motion.div>
            </motion.div>
        </nav>
    );
};

export default Navbar;

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { ShareNetwork, Clock, Calendar } from '@phosphor-icons/react';
import api from '../services/api';

const Blog = () => {
    const [posts, setPosts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedCategory, setSelectedCategory] = useState('All');

    const categories = ['All', 'Masculinity', 'Discipline', 'Campus', 'Society', 'Technology'];

    useEffect(() => {
        const fetchPosts = async () => {
            try {
                const { data } = await api.get('/blog');
                setPosts(data);
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };
        fetchPosts();
    }, []);

    const filteredPosts = selectedCategory === 'All' 
        ? posts 
        : posts.filter(post => post.category === selectedCategory);

    const featuredPost = filteredPosts[0];
    const otherPosts = filteredPosts.slice(1);

    const calculateReadingTime = (text) => {
        const wordsPerMinute = 200;
        const wordCount = (text || '').split(/\s+/).length;
        return Math.ceil(wordCount / wordsPerMinute);
    };

    const renderMediaPreview = (post, className = '') => {
        const mediaSrc = post.mediaUrl || post.featuredImage;
        if (!mediaSrc) {
            return <div className="text-muted-text text-center">No Image</div>;
        }

        if (post.mediaType === 'video') {
            return mediaSrc.match(/\.(mp4|webm|mov|avi|mkv)(\?|$)/i) ? (
                <video src={mediaSrc} controls className={className} />
            ) : (
                <div className="text-muted-text text-center p-6">Video content available</div>
            );
        }

        return <img src={mediaSrc} alt={post.title} className={className} loading="lazy" decoding="async" />;
    };

    return (
        <div className="py-12 max-w-6xl mx-auto px-4">
            {/* Header Section */}
            <motion.div
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
                className="mb-12"
            >
                <h1 className="text-4xl md:text-5xl font-heading text-primary-accent mb-4">
                    Blog / Articles
                </h1>
                <p className="text-muted-text leading-relaxed max-w-3xl">
                    The blog section displays Van Clarence's articles organized by category with filter functionality. The section header includes a title and subtitle, followed by a horizontal row of category filter pills (All, Masculinity, Discipline, Campus, Society, Technology). The active filter is highlighted with the accent color. Below the filters, a responsive grid of blog cards displays each article with a featured image, category tag, title, short excerpt, and publication date. Each card is clickable and navigates to the individual blog post page, which includes the full article text, metadata, publication date, reading time, and social sharing buttons. The blog also includes a search functionality and pagination or infinite scroll for loading additional posts.
                </p>
            </motion.div>

            {/* Category Filters */}
            <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.1 }}
                className="flex flex-wrap gap-3 mb-12 pb-6 border-b border-border"
            >
                {categories.map((category) => (
                    <button
                        key={category}
                        onClick={() => setSelectedCategory(category)}
                        className={`px-4 py-2 rounded-full text-sm font-semibold uppercase tracking-wider transition-all duration-300 ${
                            selectedCategory === category
                                ? 'bg-primary-accent text-primary-bg'
                                : 'bg-secondary-bg text-muted-text hover:text-primary-text hover:border-primary-accent border border-border'
                        }`}
                    >
                        {category}
                    </button>
                ))}
            </motion.div>

            {loading ? (
                <p className="text-center text-muted-text py-8">Loading articles...</p>
            ) : filteredPosts.length === 0 ? (
                <p className="text-center text-muted-text py-8">No blog posts in this category yet.</p>
            ) : (
                <div className="space-y-12">
                    {/* Featured Article */}
                    {featuredPost && (
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="flex flex-col md:flex-row gap-8 bg-card-bg border border-border rounded-lg overflow-hidden hover:border-primary-accent transition-all duration-300 shadow-lg"
                        >
                            {/* Featured Image */}
                            <div className="w-full md:w-2/5 bg-secondary-bg flex items-center justify-center min-h-[300px] overflow-hidden">
                                {renderMediaPreview(featuredPost, 'w-full h-full object-cover')}
                            </div>

                            {/* Featured Content */}
                            <div className="w-full md:w-3/5 p-8 flex flex-col justify-between">
                                <div>
                                    <span className="inline-block px-3 py-1 bg-secondary-bg text-xs text-primary-accent uppercase tracking-wider rounded mb-4 font-bold">
                                        {featuredPost.category || 'Uncategorized'}
                                    </span>
                                    <h2 className="text-3xl font-heading text-primary-text mb-4">{featuredPost.title}</h2>
                                    <p className="text-muted-text leading-relaxed mb-6">{featuredPost.excerpt}</p>
                                </div>

                                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 border-t border-border pt-6">
                                    <div className="flex flex-wrap gap-4 text-sm text-secondary-accent">
                                        <span className="flex items-center gap-2">
                                            <Calendar size={16} />
                                            {new Date(featuredPost.createdAt).toLocaleDateString()}
                                        </span>
                                        <span className="flex items-center gap-2">
                                            <Clock size={16} />
                                            {calculateReadingTime(featuredPost.content)} min read
                                        </span>
                                    </div>
                                    <Link
                                        to={`/blog/${featuredPost.slug || featuredPost._id}`}
                                        className="bg-primary-accent text-primary-bg px-6 py-2 rounded font-bold hover:bg-secondary-accent transition-colors uppercase text-sm"
                                    >
                                        Read Article
                                    </Link>
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {/* Blog Grid */}
                    {otherPosts.length > 0 && (
                        <div>
                            <h2 className="text-2xl font-heading text-primary-text mb-8">More Articles</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                {otherPosts.map((post, idx) => (
                                    <motion.div
                                        key={post._id}
                                        initial={{ opacity: 0, y: 20 }}
                                        whileInView={{ opacity: 1, y: 0 }}
                                        viewport={{ once: true }}
                                        transition={{ delay: idx * 0.05 }}
                                        className="bg-card-bg border border-border rounded-lg overflow-hidden hover:border-primary-accent hover:shadow-lg transition-all duration-300 flex flex-col"
                                    >
                                        {/* Card Image */}
                                        <div className="w-full h-48 bg-secondary-bg flex items-center justify-center overflow-hidden">
                                            {renderMediaPreview(post, 'w-full h-full object-cover')}
                                        </div>

                                        {/* Card Content */}
                                        <div className="p-6 flex flex-col flex-grow">
                                            <span className="inline-block px-2 py-1 bg-secondary-bg text-xs text-primary-accent uppercase tracking-wider rounded mb-3 font-bold w-fit">
                                                {post.category || 'Uncategorized'}
                                            </span>
                                            <h3 className="text-xl font-heading text-primary-text mb-3 line-clamp-2">{post.title}</h3>
                                            <p className="text-sm text-muted-text mb-4 line-clamp-2 flex-grow">{post.excerpt}</p>

                                            {/* Card Footer */}
                                            <div className="border-t border-border pt-4">
                                                <div className="flex items-center justify-between mb-4">
                                                    <div className="flex gap-3 text-xs text-secondary-accent">
                                                        <span className="flex items-center gap-1">
                                                            <Calendar size={14} />
                                                            {new Date(post.createdAt).toLocaleDateString()}
                                                        </span>
                                                        <span className="flex items-center gap-1">
                                                            <Clock size={14} />
                                                            {calculateReadingTime(post.content)} min
                                                        </span>
                                                    </div>
                                                </div>
                                                <Link
                                                    to={`/blog/${post.slug || post._id}`}
                                                    className="text-primary-accent font-semibold text-sm hover:underline"
                                                >
                                                    Read More →
                                                </Link>
                                            </div>
                                        </div>
                                    </motion.div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};
export default Blog;

